+                        // Check if returned value is a parameter that's anytype
+                        for (func.args) |arg| {
+                            if (std.mem.eql(u8, arg.name, val.name.id)) {
+                                if (param_analyzer.isParameterUsedAsFunction(func.body, arg.name)) {
+                                    returned_param_name = arg.name;
+                                    break;
+                                }
+                            }
+                        }
+                    }
+                }
+            }
+        }
